---

### 2. 예상 UserService 클래스 구조

#### 2.1 Entity 계층

```kotlin
// domain/src/main/kotlin/com/maum/backend/entity/user/UserEntity.kt

@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    // 기본 정보
    val phone: String,                      // 유니크: 전화번호
    val nickname: String,                   // 닉네임
    val email: String? = null,              // 이메일
    val passwordHash: String,               // 비밀번호

    // 상태 관리
    @Column(nullable = false)
    var status: Int = UserStatus.ACTIVE.value,  // 0=활성, 1=비활성, 2=차단

    // 프로필
    val profileImageUrl: String? = null,
    val introduction: String? = null,

    // 매칭/소셜
    @Column(name = "gender_preference")
    var genderPreference: String? = null,   // M, F, ALL

    // 감사 필드
    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),

    var deletedAt: LocalDateTime? = null,   // Soft delete
)

enum class UserStatus(val value: Int) {
    ACTIVE(0),
    INACTIVE(1),
    BANNED(2);

    companion object {
        fun fromValue(value: Int) = entries.first { it.value == value }
    }
}
```

#### 2.2 Repository 계층

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/user/UserRepository.kt

interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByPhone(phone: String): UserEntity?
    fun findByNickname(nickname: String): UserEntity?
    fun findByEmail(email: String): UserEntity?
    fun findByStatusAndDeletedAtIsNull(status: Int): List<UserEntity>
}

interface CustomUserRepository {
    fun findActiveUsers(limit: Int, offset: Int): List<UserEntity>
    fun searchByNickname(keyword: String, limit: Int): List<UserEntity>
    fun findMatchingCandidates(userId: String, gender: String, limit: Int): List<UserEntity>
}

class CustomUserRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : CustomUserRepository {
    override fun findActiveUsers(limit: Int, offset: Int): List<UserEntity> {
        val user = QUserEntity.userEntity
        return queryFactory
            .selectFrom(user)
            .where(
                user.status.eq(UserStatus.ACTIVE.value),
                user.deletedAt.isNull,
            )
            .orderBy(user.createdAt.desc())
            .limit(limit.toLong())
            .offset(offset.toLong())
            .fetch()
    }
}
```

---

### 3. Service 계층 (마이크로서비스 - user 모듈)

```kotlin
// user/src/main/kotlin/com/maum/backend/service/UserService.kt

@Service
class UserService(
    private val userRepository: UserRepository,
    private val customUserRepository: CustomUserRepository,
    private val passwordEncoder: PasswordEncoder,
    private val eventPublisher: ApplicationEventPublisher,
) {
    // 조회 (읽기 전용)
    @Transactional(readOnly = true)
    fun getUserById(id: String): UserEntity {
        return userRepository.findById(id)
            .orElseThrow { NotFoundException("User not found: $id") }
    }

    @Transactional(readOnly = true)
    fun getUserByPhone(phone: String): UserEntity {
        return userRepository.findByPhone(phone)
            ?: throw NotFoundException("User not found: $phone")
    }

    @Transactional(readOnly = true)
    fun getActiveUsers(limit: Int, offset: Int): List<UserEntity> {
        return customUserRepository.findActiveUsers(limit, offset)
    }

    @Transactional(readOnly = true)
    fun searchUsers(keyword: String, limit: Int = 20): List<UserEntity> {
        return customUserRepository.searchByNickname(keyword, limit)
    }

    // 생성/수정
    @Transactional
    fun createUser(phone: String, password: String, nickname: String): UserEntity {
        // 중복 검증
        userRepository.findByPhone(phone)?.let {
            throw ConflictException("Phone already exists: $phone")
        }

        val hashedPassword = passwordEncoder.encode(password)
        val user = UserEntity(
            phone = phone,
            nickname = nickname,
            passwordHash = hashedPassword,
            status = UserStatus.ACTIVE.value,
        )

        val saved = userRepository.save(user)

        // 이벤트 발행
        eventPublisher.publishEvent(UserCreatedEvent(userId = saved.id))

        return saved
    }

    @Transactional
    fun updateProfile(
        userId: String,
        nickname: String?,
        introduction: String?,
        genderPreference: String?,
    ): UserEntity {
        val user = getUserById(userId)

        nickname?.let { user.nickname = it }
        introduction?.let { user.introduction = it }
        genderPreference?.let { user.genderPreference = it }

        return userRepository.save(user)
    }

    @Transactional
    fun deactivateUser(userId: String): UserEntity {
        val user = getUserById(userId)
        user.status = UserStatus.INACTIVE.value
        return userRepository.save(user)
    }

    @Transactional
    fun blockUser(userId: String): UserEntity {
        val user = getUserById(userId)
        user.status = UserStatus.BANNED.value
        return userRepository.save(user)
    }
}
```

