### 4. gRPC 정의 (Proto)

```protobuf
// protobuf/src/main/proto/user/service.proto

syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserService {
  rpc GetUser(GetUserRequest) returns (GetUserResponse);
  rpc GetUserByPhone(GetUserByPhoneRequest) returns (GetUserResponse);
  rpc ListUsers(ListUsersRequest) returns (ListUsersResponse);
  rpc SearchUsers(SearchUsersRequest) returns (SearchUsersResponse);
  rpc CreateUser(CreateUserRequest) returns (CreateUserResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc DeactivateUser(DeactivateUserRequest) returns (DeactivateUserResponse);
}

message GetUserRequest {
  string user_id = 1;
}

message GetUserByPhoneRequest {
  string phone = 1;
}

message GetUserResponse {
  User user = 1;
}

message User {
  string id = 1;
  string phone = 2;
  string nickname = 3;
  string email = 4;
  int32 status = 5;
  string profile_image_url = 6;
  string introduction = 7;
  string gender_preference = 8;
  string created_at = 9;
  string updated_at = 10;
}

message ListUsersRequest {
  int32 limit = 1;
  int32 offset = 2;
}

message ListUsersResponse {
  repeated User users = 1;
  int32 total = 2;
}

message SearchUsersRequest {
  string keyword = 1;
  int32 limit = 2;
}

message SearchUsersResponse {
  repeated User users = 1;
}

message CreateUserRequest {
  string phone = 1;
  string password = 2;
  string nickname = 3;
}

message CreateUserResponse {
  User user = 1;
  string access_token = 2;
}

message UpdateProfileRequest {
  string user_id = 1;
  optional string nickname = 2;
  optional string introduction = 3;
  optional string gender_preference = 4;
}

message UpdateProfileResponse {
  User user = 1;
}

message DeactivateUserRequest {
  string user_id = 1;
}

message DeactivateUserResponse {
  bool success = 1;
}
```

