### 5. gRPC Service (Server - user 모듈)

```kotlin
// user/src/main/kotlin/com/maum/backend/controller/UserGrpcService.kt

@GrpcService
class UserGrpcService(
    private val userService: UserService,
) : UserServiceGrpc.UserServiceImplBase() {

    override fun getUser(
        request: GetUserRequest,
        responseObserver: StreamObserver<GetUserResponse>,
    ) {
        try {
            val user = userService.getUserById(request.userId)
            val response = GetUserResponse.newBuilder()
                .setUser(user.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal error")
                    .asRuntimeException()
            )
        }
    }

    override fun createUser(
        request: CreateUserRequest,
        responseObserver: StreamObserver<CreateUserResponse>,
    ) {
        try {
            val user = userService.createUser(
                phone = request.phone,
                password = request.password,
                nickname = request.nickname,
            )
            // 토큰 생성 (별도 서비스)
            val token = generateAccessToken(user.id)

            val response = CreateUserResponse.newBuilder()
                .setUser(user.toProto())
                .setAccessToken(token)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: ConflictException) {
            responseObserver.onError(
                Status.ALREADY_EXISTS
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Failed to create user")
                    .asRuntimeException()
            )
        }
    }

    // ... 다른 메서드들
}
```

---

### 6. GraphQL Schema

```graphql
# graphql/src/main/resources/graphql/user.graphqls

type User {
    id: ID!
    phone: String!
    nickname: String!
    email: String
    status: Int!
    profileImageUrl: String
    introduction: String
    genderPreference: String
    createdAt: String!
    updatedAt: String!
}

input CreateUserInput {
    phone: String!
    password: String!
    nickname: String!
}

input UpdateProfileInput {
    nickname: String
    introduction: String
    genderPreference: String
}

extend type Query {
    user(userId: ID!): User
    users(limit: Int, offset: Int): [User!]!
    searchUsers(keyword: String!, limit: Int): [User!]!
}

extend type Mutation {
    createUser(input: CreateUserInput!): AuthResponse!
    updateProfile(userId: ID!, input: UpdateProfileInput!): User!
    deactivateUser(userId: ID!): Boolean!
    blockUser(userId: ID!): Boolean!
}

type AuthResponse {
    user: User!
    accessToken: String!
    refreshToken: String!
}
```

---

### 7. GraphQL Service (Client - graphql 모듈)

```kotlin
// graphql/src/main/kotlin/com/maum/backend/service/user/UserService.kt

@Service
class UserService {

    @GrpcClient("user-grpc")
    private lateinit var userStub: UserServiceGrpc.UserServiceBlockingStub

    fun getUser(userId: String): GetUserResponse {
        return try {
            val request = GetUserRequest.newBuilder()
                .setUserId(userId)
                .build()
            userStub.getUser(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException("USER_NOT_FOUND", e.status.description)
        }
    }

    fun listUsers(limit: Int, offset: Int): ListUsersResponse {
        return try {
            val request = ListUsersRequest.newBuilder()
                .setLimit(limit)
                .setOffset(offset)
                .build()
            userStub.listUsers(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException("INTERNAL_ERROR", e.status.description)
        }
    }

    fun createUser(phone: String, password: String, nickname: String): CreateUserResponse {
        return try {
            val request = CreateUserRequest.newBuilder()
                .setPhone(phone)
                .setPassword(password)
                .setNickname(nickname)
                .build()
            userStub.createUser(request)
        } catch (e: StatusRuntimeException) {
            when (e.status.code) {
                Status.Code.ALREADY_EXISTS -> 
                    throw CustomGraphQLException("PHONE_ALREADY_EXISTS", e.status.description)
                else -> throw CustomGraphQLException("INTERNAL_ERROR", e.status.description)
            }
        }
    }
}
```

---

### 8. GraphQL Controller

```kotlin
// graphql/src/main/kotlin/com/maum/backend/controller/user/UserController.kt

@Controller
class UserController(
    private val userService: UserService,
) {

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun user(
        @Argument userId: String,
    ): UserResponse {
        val response = userService.getUser(userId)
        return response.user.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun users(
        @UserId userId: String,  // 현재 사용자
        @Argument limit: Int? = 20,
        @Argument offset: Int? = 0,
    ): List<UserResponse> {
        val response = userService.listUsers(limit ?: 20, offset ?: 0)
        return response.usersList.map { it.toResponse() }
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun searchUsers(
        @Argument keyword: String,
        @Argument limit: Int? = 20,
    ): List<UserResponse> {
        val response = userService.searchUsers(keyword, limit ?: 20)
        return response.usersList.map { it.toResponse() }
    }

    @MutationMapping
    fun createUser(
        @Argument input: CreateUserInput,
    ): AuthResponse {
        val response = userService.createUser(
            input.phone,
            input.password,
            input.nickname,
        )
        return AuthResponse(
            user = response.user.toResponse(),
            accessToken = response.accessToken,
            refreshToken = generateRefreshToken(),  // 별도 로직
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): UserResponse {
        val response = userService.updateProfile(userId, input)
        return response.user.toResponse()
    }
}
```

---

### 9. 의존성 관계도

```
GraphQL Controller (gatewayRole)
        │
        ├─→ GraphQL Service (UserService) 
        │   @GrpcClient("user-grpc")
        │
        └─→ (다른 도메인 gRPC 서비스들)
                • CallService
                • FollowService
                • ProfileService

user 마이크로서비스
        │
        ├─→ Service (UserService)
        │   @Transactional
        │
        ├─→ Repository (UserRepository)
        │   - Domain module
        │
        ├─→ gRPC Service (UserGrpcService)
        │   @GrpcService
        │
        └─→ Events (UserCreatedEvent 발행)
```

---

### 10. 주요 메서드 목록

| 계층 | 메서드명 | 역할 | 트랜잭션 |
|------|---------|------|---------|
| **Service** | `getUserById(id)` | ID로 사용자 조회 | readOnly=true |
| | `getUserByPhone(phone)` | 전화번호로 조회 | readOnly=true |
| | `getActiveUsers(limit, offset)` | 활성 사용자 목록 | readOnly=true |
| | `searchUsers(keyword)` | 닉네임 검색 | readOnly=true |
| | `createUser(phone, password, nickname)` | 회원 가입 | required |
| | `updateProfile(userId, ...)` | 프로필 수정 | required |
| | `deactivateUser(userId)` | 계정 비활성화 | required |
| | `blockUser(userId)` | 사용자 차단 | required |
| **gRPC Service** | `getUser(request)` | gRPC: 사용자 조회 | - |
| | `createUser(request)` | gRPC: 회원 가입 | - |
| | `listUsers(request)` | gRPC: 목록 조회 | - |
| **GraphQL Controller** | `user(userId)` | Query: 사용자 상세 | @PreAuthorize |
| | `users(limit, offset)` | Query: 목록 조회 | @PreAuthorize |
| | `searchUsers(keyword)` | Query: 검색 | @PreAuthorize |
| | `createUser(input)` | Mutation: 가입 | - |
| | `updateProfile(userId, input)` | Mutation: 프로필 수정 | @PreAuthorize |

---

### 11. 아키텍처 패턴

| 패턴 | 설명 | UserService 적용 |
|------|------|-----------------|
| **Repository Pattern** | DB 접근 추상화 | UserRepository, CustomUserRepository |
| **Service Pattern** | 비즈니스 로직 집중화 | UserService (@Transactional) |
| **gRPC Service Pattern** | 서비스 간 통신 | UserGrpcService (@GrpcService) |
| **GraphQL Gateway Pattern** | API 조합 및 인증 | GraphQL Controller + Service |
| **Event-Driven** | 비동기 이벤트 | UserCreatedEvent 발행 |
| **Soft Delete** | 논리적 삭제 | deletedAt 컬럼 |
| **Transactional** | 원자성 보장 | @Transactional(readOnly=true/required) |

---

### 12. 주요 고려사항

| 항목 | 설명 |
|------|------|
| **보안** | 비밀번호 해싱 (PasswordEncoder), @PreAuthorize 사용 |
| **N+1 문제** | LAZY 페칭 + QueryDSL 최적화 또는 DataLoader 패턴 |
| **캐싱** | Redis에서 자주 조회되는 사용자 정보 캐시 권장 |
| **검증** | 중복 검사 (phone, nickname), 상태 전이 검증 |
| **에러 처리** | gRPC Status 코드 적절히 매핑 |
| **이벤트** | 회원가입 시 UserCreatedEvent 발행 → 다른 서비스 구독 |
| **Soft Delete** | 조회 시 deletedAt.isNull 조건 항상 포함 |

