@Entity
@Table(catalog = "maum", name = "user")
class UserEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    // 기본 정보
    val phone: String,                      // 유니크: 전화번호
    val nickname: String,                   // 닉네임
    val email: String? = null,              // 이메일
    val passwordHash: String,               // 비밀번호

    // 상태 관리
    @Column(nullable = false)
    var status: Int = UserStatus.ACTIVE.value,  // 0=활성, 1=비활성, 2=차단

    // 프로필
    val profileImageUrl: String? = null,
    val introduction: String? = null,

    // 매칭/소셜
    @Column(name = "gender_preference")
    var genderPreference: String? = null,   // M, F, ALL

    // 감사 필드
    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),

    var deletedAt: LocalDateTime? = null,   // Soft delete
)

enum class UserStatus(val value: Int) {
    ACTIVE(0),
    INACTIVE(1),
    BANNED(2);

    companion object {
        fun fromValue(value: Int) = entries.first { it.value == value }
    }
}
