#### 2.2 Repository 계층

```kotlin
// domain/src/main/kotlin/com/maum/backend/repository/user/UserRepository.kt

interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByPhone(phone: String): UserEntity?
    fun findByNickname(nickname: String): UserEntity?
    fun findByEmail(email: String): UserEntity?
    fun findByStatusAndDeletedAtIsNull(status: Int): List<UserEntity>
}

interface CustomUserRepository {
    fun findActiveUsers(limit: Int, offset: Int): List<UserEntity>
    fun searchByNickname(keyword: String, limit: Int): List<UserEntity>
    fun findMatchingCandidates(userId: String, gender: String, limit: Int): List<UserEntity>
}

class CustomUserRepositoryImpl(
    private val queryFactory: JPAQueryFactory,
) : CustomUserRepository {
    override fun findActiveUsers(limit: Int, offset: Int): List<UserEntity> {
        val user = QUserEntity.userEntity
        return queryFactory
            .selectFrom(user)
            .where(
                user.status.eq(UserStatus.ACTIVE.value),
                user.deletedAt.isNull,
            )
            .orderBy(user.createdAt.desc())
            .limit(limit.toLong())
            .offset(offset.toLong())
            .fetch()
    }
}
