### 5. gRPC Service (Server - user 모듈)

```kotlin
// user/src/main/kotlin/com/maum/backend/controller/UserGrpcService.kt

@GrpcService
class UserGrpcService(
    private val userService: UserService,
) : UserServiceGrpc.UserServiceImplBase() {

    override fun getUser(
        request: GetUserRequest,
        responseObserver: StreamObserver<GetUserResponse>,
    ) {
        try {
            val user = userService.getUserById(request.userId)
            val response = GetUserResponse.newBuilder()
                .setUser(user.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal error")
                    .asRuntimeException()
            )
        }
    }

    override fun createUser(
        request: CreateUserRequest,
        responseObserver: StreamObserver<CreateUserResponse>,
    ) {
        try {
            val user = userService.createUser(
                phone = request.phone,
                password = request.password,
                nickname = request.nickname,
            )
            // 토큰 생성 (별도 서비스)
            val token = generateAccessToken(user.id)

            val response = CreateUserResponse.newBuilder()
                .setUser(user.toProto())
                .setAccessToken(token)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: ConflictException) {
            responseObserver.onError(
                Status.ALREADY_EXISTS
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Failed to create user")
                    .asRuntimeException()
            )
        }
    }

    // ... 다른 메서드들
}
