### 7. GraphQL Service (Client - graphql 모듈)

```kotlin
// graphql/src/main/kotlin/com/maum/backend/service/user/UserService.kt

@Service
class UserService {

    @GrpcClient("user-grpc")
    private lateinit var userStub: UserServiceGrpc.UserServiceBlockingStub

    fun getUser(userId: String): GetUserResponse {
        return try {
            val request = GetUserRequest.newBuilder()
                .setUserId(userId)
                .build()
            userStub.getUser(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException("USER_NOT_FOUND", e.status.description)
        }
    }

    fun listUsers(limit: Int, offset: Int): ListUsersResponse {
        return try {
            val request = ListUsersRequest.newBuilder()
                .setLimit(limit)
                .setOffset(offset)
                .build()
            userStub.listUsers(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException("INTERNAL_ERROR", e.status.description)
        }
    }

    fun createUser(phone: String, password: String, nickname: String): CreateUserResponse {
        return try {
            val request = CreateUserRequest.newBuilder()
                .setPhone(phone)
                .setPassword(password)
                .setNickname(nickname)
                .build()
            userStub.createUser(request)
        } catch (e: StatusRuntimeException) {
            when (e.status.code) {
                Status.Code.ALREADY_EXISTS -> 
                    throw CustomGraphQLException("PHONE_ALREADY_EXISTS", e.status.description)
                else -> throw CustomGraphQLException("INTERNAL_ERROR", e.status.description)
            }
        }
    }
}
