### 8. GraphQL Controller

```kotlin
// graphql/src/main/kotlin/com/maum/backend/controller/user/UserController.kt

@Controller
class UserController(
    private val userService: UserService,
) {

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun user(
        @Argument userId: String,
    ): UserResponse {
        val response = userService.getUser(userId)
        return response.user.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun users(
        @UserId userId: String,  // 현재 사용자
        @Argument limit: Int? = 20,
        @Argument offset: Int? = 0,
    ): List<UserResponse> {
        val response = userService.listUsers(limit ?: 20, offset ?: 0)
        return response.usersList.map { it.toResponse() }
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun searchUsers(
        @Argument keyword: String,
        @Argument limit: Int? = 20,
    ): List<UserResponse> {
        val response = userService.searchUsers(keyword, limit ?: 20)
        return response.usersList.map { it.toResponse() }
    }

    @MutationMapping
    fun createUser(
        @Argument input: CreateUserInput,
    ): AuthResponse {
        val response = userService.createUser(
            input.phone,
            input.password,
            input.nickname,
        )
        return AuthResponse(
            user = response.user.toResponse(),
            accessToken = response.accessToken,
            refreshToken = generateRefreshToken(),  // 별도 로직
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): UserResponse {
        val response = userService.updateProfile(userId, input)
        return response.user.toResponse()
    }
}
